// Domain model types for the 平安扣 Pinankou safety app.
// Entities are plain data classes so they serialize cleanly to preferences.

export type RiskLevel = 'low' | 'medium' | 'high' | 'critical';
export type HazardStatus = 'reported' | 'rectifying' | 'pending_accept' | 'closed';
export type SafetyItemStatus = 'open' | 'in_progress' | 'done';
export type SafetyItemType = 'fire' | 'equipment' | 'passage' | 'training' | 'other';
export type RectificationStatus = 'pending' | 'in_progress' | 'pending_accept' | 'closed';
export type DashboardTimeRange = 'week' | 'month' | 'all';

export function riskLevelLabel(l: RiskLevel): string {
  if (l === 'low') {
    return '低';
  } else if (l === 'medium') {
    return '中';
  } else if (l === 'high') {
    return '高';
  }
  return '重大';
}

export function riskLevelColor(l: RiskLevel): string {
  if (l === 'low') {
    return '#2E9E84';
  } else if (l === 'medium') {
    return '#E0A23B';
  } else if (l === 'high') {
    return '#E06A3B';
  }
  return '#C2353F';
}

export function hazardStatusLabel(s: HazardStatus): string {
  if (s === 'reported') {
    return '已上报';
  } else if (s === 'rectifying') {
    return '整改中';
  } else if (s === 'pending_accept') {
    return '待验收';
  }
  return '已闭环';
}

export function hazardStatusColor(s: HazardStatus): string {
  if (s === 'closed') {
    return '#2E9E84';
  } else if (s === 'pending_accept') {
    return '#E0A23B';
  } else if (s === 'rectifying') {
    return '#2D7DE0';
  }
  return '#C2353F';
}

export function safetyItemStatusLabels(s: SafetyItemStatus): string {
  if (s === 'open') {
    return '待处理';
  } else if (s === 'in_progress') {
    return '进行中';
  }
  return '已完成';
}

export function safetyItemTypeLabel(t: SafetyItemType): string {
  if (t === 'fire') {
    return '消防';
  } else if (t === 'equipment') {
    return '设备';
  } else if (t === 'passage') {
    return '通道';
  } else if (t === 'training') {
    return '培训';
  }
  return '其他';
}

export function rectificationStatusLabel(s: RectificationStatus): string {
  if (s === 'pending') {
    return '待整改';
  } else if (s === 'in_progress') {
    return '整改中';
  } else if (s === 'pending_accept') {
    return '待验收';
  }
  return '已闭环';
}

export function rectificationStatusColor(s: RectificationStatus): string {
  if (s === 'closed') {
    return '#2E9E84';
  } else if (s === 'pending_accept') {
    return '#E0A23B';
  } else if (s === 'in_progress') {
    return '#2D7DE0';
  }
  return '#C2353F';
}

export function isHazardOpen(s: HazardStatus): boolean {
  return s !== 'closed';
}

export class SafetyItem {
  id: string = '';
  title: string = '';
  type: SafetyItemType = 'other';
  status: SafetyItemStatus = 'open';
  deadline: string = '';
  description: string = '';
  createdAt: number = 0;

  constructor(id: string, title: string, type: SafetyItemType, deadline: string, description: string) {
    this.id = id;
    this.title = title;
    this.type = type;
    this.status = 'open';
    this.deadline = deadline;
    this.description = description;
    this.createdAt = Date.now();
  }
}

export class Hazard {
  id: string = '';
  title: string = '';
  level: RiskLevel = 'medium';
  location: string = '';
  description: string = '';
  photos: string[] = [];
  status: HazardStatus = 'reported';
  createdAt: number = 0;

  constructor(id: string, title: string, level: RiskLevel, location: string, description: string, photos: string[]) {
    this.id = id;
    this.title = title;
    this.level = level;
    this.location = location;
    this.description = description;
    this.photos = photos;
    this.status = 'reported';
    this.createdAt = Date.now();
  }
}

export class PatrolTask {
  id: string = '';
  name: string = '';
  location: string = '';
  done: boolean = false;

  constructor(id: string, name: string, location: string) {
    this.id = id;
    this.name = name;
    this.location = location;
    this.done = false;
  }
}

export class PatrolRecord {
  id: string = '';
