  constructor(id: string, name: string, role: string, phone: string) {
    this.id = id;
    this.name = name;
    this.role = role;
    this.phone = phone;
  }
}

export class Rectification {
  id: string = '';
  sourceTitle: string = '';
  assignee: string = '';
  status: RectificationStatus = 'pending';
  deadline: string = '';
  remark: string = '';
  createdAt: number = 0;

  constructor(id: string, sourceTitle: string, assignee: string, deadline: string) {
    this.id = id;
    this.sourceTitle = sourceTitle;
    this.assignee = assignee;
    this.deadline = deadline;
    this.status = 'pending';
    this.remark = '';
    this.createdAt = Date.now();
  }
}

export function genId(prefix: string): string {
  return prefix + '_' + Date.now().toString() + '_' + Math.floor(Math.random() * 10000).toString();
}

export function formatDate(ts: number): string {
  if (ts <= 0) {
    return '';
  }
  const d = new Date(ts);
  const m: string = (d.getMonth() + 1) < 10 ? '0' + (d.getMonth() + 1).toString() : (d.getMonth() + 1).toString();
  const day: string = d.getDate() < 10 ? '0' + d.getDate().toString() : d.getDate().toString();
  const hh: string = d.getHours() < 10 ? '0' + d.getHours().toString() : d.getHours().toString();
  const mm: string = d.getMinutes() < 10 ? '0' + d.getMinutes().toString() : d.getMinutes().toString();
  return d.getFullYear().toString() + '-' + m + '-' + day + ' ' + hh + ':' + mm;
}

export function formatDateShort(ts: number): string {
  if (ts <= 0) {
    return '';
  }
  const d = new Date(ts);
  const m: string = (d.getMonth() + 1) < 10 ? '0' + (d.getMonth() + 1).toString() : (d.getMonth() + 1).toString();
  const day: string = d.getDate() < 10 ? '0' + d.getDate().toString() : d.getDate().toString();
  return d.getFullYear().toString() + '-' + m + '-' + day;
}

export function startOfDay(ts: number): number {
  const d = new Date(ts);
  d.setHours(0, 0, 0, 0);
  return d.getTime();
}

