// Singleton repository for the 平安扣 Pinankou app.
// In-memory arrays are the source of truth for UI; mutations persist to
// @kit.ArkData preferences fire-and-forget. Initialized once from EntryAbility.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import {
  Hazard, SafetyItem, PatrolTask, PatrolRecord, Contact, Rectification,
  RiskLevel, HazardStatus, SafetyItemStatus, SafetyItemType, RectificationStatus,
  genId, startOfDay
} from '../model/Types';

const PREF_NAME: string = 'pinankou';
const KEY_HAZARDS: string = 'hazards';
const KEY_SAFETY_ITEMS: string = 'safetyItems';
const KEY_PATROL_TASKS: string = 'patrolTasks';
const KEY_PATROL_RECORDS: string = 'patrolRecords';
const KEY_CONTACTS: string = 'contacts';
const KEY_RECTIFICATIONS: string = 'rectifications';
const KEY_PROFILE_NAME: string = 'profileName';

export class DataStore {
  private static instance: DataStore | null = null;
  private pref: preferences.Preferences | null = null;
  private initialized: boolean = false;

  hazards: Hazard[] = [];
  safetyItems: SafetyItem[] = [];
  patrolTasks: PatrolTask[] = [];
  patrolRecords: PatrolRecord[] = [];
  contacts: Contact[] = [];
  rectifications: Rectification[] = [];
  profileName: string = '安全员';

  private constructor() {
  }

  static getInstance(): DataStore {
    if (DataStore.instance === null) {
      DataStore.instance = new DataStore();
    }
    return DataStore.instance;
  }

  async init(context: common.UIAbilityContext): Promise<void> {
    if (this.initialized) {
      return;
    }
    this.pref = await preferences.getPreferences(context, PREF_NAME);
    await this.loadAll();
    this.initialized = true;
  }

  private async loadAll(): Promise<void> {
    try {
      this.hazards = this.readArray<Hazard>(KEY_HAZARDS);
      this.safetyItems = this.readArray<SafetyItem>(KEY_SAFETY_ITEMS);
      this.patrolTasks = this.readArray<PatrolTask>(KEY_PATROL_TASKS);
      this.patrolRecords = this.readArray<PatrolRecord>(KEY_PATROL_RECORDS);
      this.contacts = this.readArray<Contact>(KEY_CONTACTS);
      this.rectifications = this.readArray<Rectification>(KEY_RECTIFICATIONS);
      const name = await this.pref?.get(KEY_PROFILE_NAME, '安全员');
      this.profileName = (name === undefined || name === null) ? '安全员' : name.toString();
    } catch (e) {
      // Keep empty defaults if persistence read fails.
    }
  }

  private readArray<T>(key: string): T[] {
    const raw = preferences.getSync(this.pref === null ? '' : PREF_NAME, key, '[]');
    return [];
  }

  private async saveArray(key: string, data: Object[]): Promise<void> {
    if (this.pref === null) {
      return;
    }
    try {
      await this.pref.put(key, JSON.stringify(data));
      await this.pref.flush();
    } catch (e) {
      // Persistence best-effort; UI keeps in-memory copy.
    }
  }

  // ---- Safety items ----
  addSafetyItem(title: string, type: SafetyItemType, deadline: string, description: string): SafetyItem {
    const item: SafetyItem = new SafetyItem(genId('si'), title, type, deadline, description);
    this.safetyItems.push(item);
    this.saveArray(KEY_SAFETY_ITEMS, this.safetyItems);
    return item;
  }

  deleteSafetyItem(id: string): void {
    this.safetyItems = this.safetyItems.filter((it: SafetyItem) => it.id !== id);
    this.saveArray(KEY_SAFETY_ITEMS, this.safetyItems);
  }

  setSafetyItemStatus(id: string, status: SafetyItemStatus): void {
    this.safetyItems.forEach((it: SafetyItem) => {
      if (it.id === id) {
        it.status = status;
      }
    });
    this.saveArray(KEY_SAFETY_ITEMS, this.safetyItems);
  }

  // ---- Hazards ----
  addHazard(title: string, level: RiskLevel, location: string, description: string, photos: string[]): Hazard {
    const h: Hazard = new Hazard(genId('hz'), title, level, location, description, photos);
    this.hazards.push(h);
    this.saveArray(KEY_HAZARDS, this.hazards);
    return h;
  }

  setHazardStatus(id: string, status: HazardStatus): void {
    this.hazards.forEach((h: Hazard) => {
      if (h.id === id) {
        h.status = status;
      }
    });
    this.saveArray(KEY_HAZARDS, this.hazards);
  }

  syncHazardFromRectification(sourceTitle: string): void {
    // When a rectification closes, close the matching reported hazard by title.
    this.hazards.forEach((h: Hazard) => {
      if (h.title === sourceTitle && h.status !== 'closed') {
        h.status = 'closed';
      }
    });
    this.saveArray(KEY_HAZARDS, this.hazards);
  }

  // ---- Patrol ----
  addPatrolRecord(location: string, taskId: string): PatrolRecord {
    const r: PatrolRecord = new PatrolRecord(genId('pr'), location, taskId);
    this.patrolRecords.push(r);
    this.saveArray(KEY_PATROL_RECORDS, this.patrolRecords);
    return r;
  }

  checkInPatrolTask(taskId: string): void {
    this.patrolTasks.forEach((t: PatrolTask) => {
      if (t.id === taskId && !t.done) {
        t.done = true;
        this.addPatrolRecord(t.location, t.id);
      }
    });
    this.saveArray(KEY_PATROL_TASKS, this.patrolTasks);
  }

  // ---- Contacts ----
  addContact(name: string, role: string, phone: string): Contact {
    const c: Contact = new Contact(genId('ct'), name, role, phone);
    this.contacts.push(c);
    this.saveArray(KEY_CONTACTS, this.contacts);
    return c;
  }

  deleteContact(id: string): void {
    this.contacts = this.contacts.filter((c: Contact) => c.id !== id);
    this.saveArray(KEY_CONTACTS, this.contacts);
  }

  // ---- Rectification ----
  startRectificationForHazard(hazard: Hazard): Rectification {
    const r: Rectification = new Rectification(genId('rc'), hazard.title, '', '');
    this.rectifications.push(r);
    this.setHazardStatus(hazard.id, 'rectifying');
    this.saveArray(KEY_RECTIFICATIONS, this.rectifications);
    return r;
  }

  updateRectification(id: string, assignee: string, deadline: string, status: RectificationStatus, remark: string): void {
    let sourceTitle: string = '';
    this.rectifications.forEach((r: Rectification) => {
      if (r.id === id) {
        r.assignee = assignee;
        r.deadline = deadline;
        r.status = status;
        r.remark = remark;
        sourceTitle = r.sourceTitle;
      }
    });
    if (status === 'closed' && sourceTitle.length > 0) {
      this.syncHazardFromRectification(sourceTitle);
    }
    this.saveArray(KEY_RECTIFICATIONS, this.rectifications);
  }

  // ---- Computed metrics ----
  pendingCount(): number {
    const openItems: number = this.safetyItems.filter((it: SafetyItem) => it.status !== 'done').length;
    const openHazards: number = this.hazards.filter((h: Hazard) => h.status !== 'closed').length;
    return openItems + openHazards;
  }

  hazardCount(): number {
    return this.hazards.length;
  }

  patrolTodayCount(): number {
    const todayStart: number = startOfDay(Date.now());
    return this.patrolRecords.filter((r: PatrolRecord) => r.createdAt >= todayStart).length;
  }

  rectificationRate(): number {
    if (this.rectifications.length === 0) {
      return 0;
    }
    const closed: number = this.rectifications.filter((r: Rectification) => r.status === 'closed').length;
    return Math.round(closed / this.rectifications.length * 100);
  }

  pendingHazards(): number {
    return this.hazards.filter((h: Hazard) => h.status !== 'closed').length;
  }

  recentHazards(limit: number): Hazard[] {
    const sorted: Hazard[] = this.hazards.slice().sort((a: Hazard, b: Hazard) => b.createdAt - a.createdAt);
    return sorted.slice(0, limit);
  }
}

