// Index.ets — 平安扣 Pinankou app shell.
// Owns tab state and surface switching for the fixed BottomTabBar shell.
// Tab surfaces: home, hazards, patrol, rectification, profile.
// Non-tab surfaces (safety-items, contacts, dashboard) replace the tab view.

import { Theme } from '../common/Theme';
import { TabId } from '../common/TabTypes';
import { BottomTabBar } from '../components/BottomTabBar';

import { HomePage } from '../pages/Home';
import { HazardsPage } from '../pages/Hazards';
import { PatrolPage } from '../pages/Patrol';
import { RectificationPage } from '../pages/Rectification';
import { ProfilePage } from '../pages/Profile';
import { SafetyItemsPage } from '../pages/SafetyItems';
import { ContactsPage } from '../pages/Contacts';
import { DashboardPage } from '../pages/Dashboard';

type AppSurface =
  | 'home'
  | 'hazards'
  | 'patrol'
  | 'rectification'
  | 'profile'
  | 'safety-items'
  | 'contacts'
  | 'dashboard';

@Entry
@Component
struct Index {
  @State surface: AppSurface = 'home';
  @State activeTab: TabId = 'tab-home';
  @State lastTabBeforePush: TabId = 'tab-home';

  build() {
    Stack() {
      Stack({ alignContent: Alignment.Bottom }) {
        Column() {
          this.CurrentSurface()
        }
        .width('100%')
        .height('100%')
        .padding({
          bottom: this.isTabSurface(this.surface) ? Theme.bottomTabHeight + 16 : 0
        })

        if (this.isTabSurface(this.surface)) {
          BottomTabBar({
            activeTab: this.activeTab,
            onTap: (tab: TabId): void => this.goToTab(tab),
          })
        }
      }
      .width('100%')
      .height('100%')
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  CurrentSurface() {
    if (this.surface === 'home') {
      HomePage({
        goToSafetyItems: (): void => this.openNonTab('safety-items'),
        goToHazards: (): void => this.goToTab('tab-hazards'),
        goToPatrol: (): void => this.goToTab('tab-patrol'),
        goToContacts: (): void => this.openNonTab('contacts'),
      })
    } else if (this.surface === 'hazards') {
      HazardsPage({
        startRectification: (): void => this.goToTab('tab-rectification'),
      })
    } else if (this.surface === 'patrol') {
      PatrolPage()
    } else if (this.surface === 'rectification') {
      RectificationPage()
    } else if (this.surface === 'profile') {
      ProfilePage({
        goToContacts: (): void => this.openNonTab('contacts'),
        goToDashboard: (): void => this.openNonTab('dashboard'),
      })
    } else if (this.surface === 'safety-items') {
      SafetyItemsPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
      })
    } else if (this.surface === 'contacts') {
      ContactsPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
      })
    } else if (this.surface === 'dashboard') {
      DashboardPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
      })
    }
  }

  private isTabSurface(s: AppSurface): boolean {
    return s === 'home' || s === 'hazards' || s === 'patrol' || s === 'rectification' || s === 'profile';
  }

  private goToTab(tab: TabId): void {
    this.activeTab = tab;
    if (tab === 'tab-home') {
      this.surface = 'home';
    } else if (tab === 'tab-hazards') {
      this.surface = 'hazards';
    } else if (tab === 'tab-patrol') {
      this.surface = 'patrol';
    } else if (tab === 'tab-rectification') {
      this.surface = 'rectification';
    } else if (tab === 'tab-profile') {
      this.surface = 'profile';
    }
  }

  private openNonTab(s: AppSurface): void {
    this.lastTabBeforePush = this.activeTab;
    this.surface = s;
  }

  private returnToTab(tab: TabId): void {
    this.goToTab(tab);
  }
}

