// Reusable UI primitives for 平安扣 Pinankou pages.
import { Theme } from '../common/Theme';

@Component
export struct StatusBadge {
  @Prop label: string = '';
  @Prop color: string = Theme.info;

  build() {
    Text(this.label)
      .fontSize(11)
      .fontWeight(FontWeight.Medium)
      .fontColor(this.color)
      .padding({ left: 8, right: 8, top: 3, bottom: 3 })
      .borderRadius(Theme.radiusTiny)
      .backgroundColor(this.colorWithAlpha(this.color))
  }

  private colorWithAlpha(c: string): string {
    // Light tint background derived from the badge text color.
    if (c === Theme.success) {
      return '#E2F4EF';
    } else if (c === Theme.danger) {
      return '#FBE7E9';
    } else if (c === Theme.warning) {
      return '#FBF1DF';
    } else if (c === Theme.info) {
      return '#E4EEFB';
    }
    return Theme.chipSoftBg;
  }
}

@Component
export struct EmptyState {
  @Prop title: string = '暂无数据';
  @Prop hint: string = '';

  build() {
    Column() {
      Text('○')
        .fontSize(56)
        .fontColor(Theme.borderDefault)
        .margin({ bottom: 12 })
      Text(this.title)
        .fontSize(15)
        .fontColor(Theme.textTertiary)
      if (this.hint.length > 0) {
        Text(this.hint)
          .fontSize(12)
          .fontColor(Theme.textQuaternary)
          .margin({ top: 6 })
      }
    }
    .width('100%')
    .padding({ top: 48, bottom: 48 })
    .alignItems(HorizontalAlign.Center)
  }
}

@Component
export struct MetricCard {
  @Prop label: string = '';
  @Prop value: string = '';
  @Prop accent: string = Theme.brandPrimary;
  idValue: string = '';

  build() {
    Column({ space: 6 }) {
      Text(this.label)
        .fontSize(12)
        .fontColor(Theme.textSecondary)
      Text(this.value)
        .fontSize(26)
        .fontWeight(FontWeight.Bold)
        .fontColor(this.accent)
    }
    .id(this.idValue)
    .width('100%')
    .padding({ top: 16, bottom: 16, left: 12, right: 12 })
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }
}

@Component
export struct SectionHeader {
  @Prop title: string = '';
  actionText: string = '';
  onAction: () => void = () => {};

  build() {
    Row() {
      Text(this.title)
        .fontSize(16)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Blank()
      if (this.actionText.length > 0) {
        Text(this.actionText)
          .fontSize(13)
          .fontColor(Theme.brandPrimary)
          .onClick(() => this.onAction())
      }
    }
    .width('100%')
    .alignItems(VerticalAlign.Center)
  }
}

@Component
export struct PageHeader {
  @Prop title: string = '';
  onBack: () => void = () => {};
  showBack: boolean = true;
  actionText: string = '';
  onAction: () => void = () => {};

  build() {
    Row() {
      if (this.showBack) {
        Text('‹ 返回')
          .fontSize(15)
          .fontColor(Theme.brandPrimary)
          .onClick(() => this.onBack())
      }
      Text(this.title)
        .fontSize(17)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .layoutWeight(1)
        .textAlign(this.showBack ? TextAlign.Center : TextAlign.Start)
      if (this.actionText.length > 0) {
        Text(this.actionText)
          .fontSize(15)
          .fontColor(Theme.brandPrimary)
          .onClick(() => this.onAction())
      }
    }
    .width('100%')
    .height(48)
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .alignItems(VerticalAlign.Center)
    .backgroundColor(Theme.cardBg)
  }
}

