import { Theme, BrandGradient } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import { Hazard, riskLevelLabel, riskLevelColor, hazardStatusLabel, hazardStatusColor, formatDate, SafetyItemType } from '../model/Types';
import { MetricCard, SectionHeader, EmptyState, StatusBadge } from '../components/Common';
import { showToast } from '../common/Toast';

interface QuickAction {
  id: string;
  label: string;
}

const QUICK_ACTIONS: QuickAction[] = [
  { id: 'home-quick-action-safety-items', label: '安全事项' },
  { id: 'home-quick-action-hazards', label: '隐患上报' },
  { id: 'home-quick-action-patrol', label: '巡检打卡' },
  { id: 'home-quick-action-contacts', label: '应急联系' },
];

const ITEM_TYPES: SafetyItemType[] = ['fire', 'equipment', 'passage', 'training', 'other'];

@Component
export struct HomePage {
  goToSafetyItems: () => void = () => {};
  goToHazards: () => void = () => {};
  goToPatrol: () => void = () => {};
  goToContacts: () => void = () => {};

  @State pendingCount: number = 0;
  @State hazardCount: number = 0;
  @State rectificationRate: number = 0;
  @State recentHazards: Hazard[] = [];
  @State showAddSheet: boolean = false;

  @State formTitle: string = '';
  @State formType: SafetyItemType = 'fire';
  @State formDeadline: string = '';
  @State formDescription: string = '';

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
    this.pendingCount = this.store.pendingCount();
    this.hazardCount = this.store.hazardCount();
    this.rectificationRate = this.store.rectificationRate();
    this.recentHazards = this.store.recentHazards(5);
  }

  private onQuickAction(id: string): void {
    if (id === 'home-quick-action-safety-items') {
      this.goToSafetyItems();
    } else if (id === 'home-quick-action-hazards') {
      this.goToHazards();
    } else if (id === 'home-quick-action-patrol') {
      this.goToPatrol();
    } else if (id === 'home-quick-action-contacts') {
      this.goToContacts();
    }
  }

  private saveSafetyItem(): void {
    if (this.formTitle.trim().length === 0) {
      showToast('请填写事项标题');
      return;
    }
    this.store.addSafetyItem(this.formTitle.trim(), this.formType, this.formDeadline.trim(), this.formDescription.trim());
    this.formTitle = '';
    this.formType = 'fire';
    this.formDeadline = '';
    this.formDescription = '';
    this.showAddSheet = false;
    this.refresh();
    showToast('已保存安全事项');
  }

  build() {
    Column() {
      this.Header()
      Scroll() {
        Column({ space: 14 }) {
          this.SummaryBoard()
          this.QuickActions()
          this.RecentSection()
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 24 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  Header() {
    Row() {
      Column() {
        Text('平安扣')
          .fontSize(22)
          .fontWeight(FontWeight.Bold)
          .fontColor('#FFFFFF')
        Text('Pinankou · 安全管理')
          .fontSize(12)
          .fontColor('rgba(255,255,255,0.85)')
          .margin({ top: 2 })
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)
      Text(this.store.profileName)
        .fontSize(13)
        .fontColor('#FFFFFF')
        .padding({ left: 12, right: 12, top: 6, bottom: 6 })
        .borderRadius(Theme.radiusButton)
        .backgroundColor('rgba(255,255,255,0.18)')
    }
    .id('home-header-title')
    .width('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 28, bottom: 24 })
    .linearGradient(BrandGradient.primary)
    .alignItems(VerticalAlign.Center)
  }

  @Builder
  SummaryBoard() {
    Column({ space: 12 }) {
      Row({ space: 10 }) {
        Column() {
          this.Metric('home-summary-pending-count', '今日待办', this.pendingCount.toString(), Theme.warning)
        }.layoutWeight(1)
        Column() {
          this.Metric('home-summary-hazard-count', '隐患总数', this.hazardCount.toString(), Theme.danger)
        }.layoutWeight(1)
      }.width('100%')
      Row() {
        Column() {
          Text('整改闭环率')
            .fontSize(12)
            .fontColor('#FFFFFF')
          Row() {
            Text(this.rectificationRate.toString())
              .fontSize(28)
              .fontWeight(FontWeight.Bold)
              .fontColor('#FFFFFF')
            Text('%')
              .fontSize(14)
              .fontColor('rgba(255,255,255,0.85)')
              .margin({ left: 2, bottom: 4 })
          }.alignItems(VerticalAlign.Bottom)
        }
        .id('home-summary-rectification-rate')
        .width('100%')
        .alignItems(HorizontalAlign.Start)
        .linearGradient(BrandGradient.accent)
        .padding({ top: 16, bottom: 16, left: 16, right: 16 })
        .borderRadius(Theme.radiusCard)
      }.width('100%')
    }
  }

  @Builder
  Metric(idValue: string, label: string, value: string, accent: string) {
    Column({ space: 6 }) {
      Text(label)
        .fontSize(12)
        .fontColor(Theme.textSecondary)
      Text(value)
        .fontSize(26)
        .fontWeight(FontWeight.Bold)
        .fontColor(accent)
    }
    .id(idValue)
    .width('100%')
    .padding({ top: 16, bottom: 16, left: 14, right: 14 })
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  QuickActions() {
    Column({ space: 10 }) {
      SectionHeader({ title: '快捷入口' })
      Grid() {
        ForEach(QUICK_ACTIONS, (a: QuickAction) => {
          GridItem() {
            Column({ space: 8 }) {
              Text(a.label.charAt(0))
                .fontSize(20)
                .fontWeight(FontWeight.Bold)
                .fontColor('#FFFFFF')
                .width(40)
                .height(40)
                .textAlign(TextAlign.Center)
                .borderRadius(20)
                .backgroundColor(Theme.brandPrimary)
              Text(a.label)
                .fontSize(13)
                .fontColor(Theme.textPrimary)
            }
            .id(a.id)
            .width('100%')
            .padding({ top: 14, bottom: 14 })
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBg)
            .alignItems(HorizontalAlign.Center)
            .onClick(() => this.onQuickAction(a.id))
          }
        }, (a: QuickAction) => a.id)
      }
      .columnsTemplate('1fr 1fr 1fr 1fr')
      .rowsGap(10)
      .columnsGap(10)
      .height(96)
    }
  }

  @Builder
  RecentSection() {
    Column({ space: 10 }) {
      SectionHeader({ title: '最近隐患', actionText: '查看全部', onAction: (): void => this.goToHazards() })
      Column({ space: 10 }) {
        if (this.recentHazards.length === 0) {
          EmptyState({ title: '暂无隐患', hint: '点击「隐患上报」记录新隐患' })
            .id('home-recent-empty')
        } else {
          ForEach(this.recentHazards, (h: Hazard) => {
            Row() {
              Column({ space: 4 }) {
                Text(h.title)
                  .fontSize(15)
                  .fontWeight(FontWeight.Medium)
                  .fontColor(Theme.textPrimary)
                  .maxLines(1)
                  .textOverflow({ overflow: TextOverflow.Ellipsis })
                Row({ space: 8 }) {
                  Text(h.location.length > 0 ? h.location : '未填位置')
                    .fontSize(12)
                    .fontColor(Theme.textTertiary)
                  Text(formatDate(h.createdAt))
                    .fontSize(12)
                    .fontColor(Theme.textTertiary)
                }
              }
              .alignItems(HorizontalAlign.Start)
              .layoutWeight(1)
              Column({ space: 4 }) {
                StatusBadge({ label: riskLevelLabel(h.level), color: riskLevelColor(h.level) })
                StatusBadge({ label: hazardStatusLabel(h.status), color: hazardStatusColor(h.status) })
              }
              .alignItems(HorizontalAlign.End)
            }
            .id('home-recent-hazard-' + h.id)
            .width('100%')
            .padding(14)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBg)
            .alignItems(VerticalAlign.Top)
            .onClick(() => this.goToHazards())
          }, (h: Hazard) => h.id)
        }
      }
      .id('home-recent-hazard-list')
      .width('100%')

      Button('新建安全事项')
        .id('home-add-safety-item')
        .width('100%')
        .height(46)
        .backgroundColor(Theme.brandPrimary)
        .fontColor('#FFFFFF')
        .fontSize(15)
        .borderRadius(Theme.radiusButton)
        .margin({ top: 6 })
        .onClick(() => {
          this.showAddSheet = true;
        })
        .bindSheet($$this.showAddSheet, this.AddSheet(), {
          height: '70%',
          dragBar: true
        })
    }
  }

  @Builder
  AddSheet() {
    Column({ space: 14 }) {
      Text('新建安全事项')
        .fontSize(17)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Column({ space: 8 }) {
        Text('标题')
          .fontSize(13)
          .fontColor(Theme.textSecondary)
        TextInput({ text: this.formTitle, placeholder: '如：消防通道占用' })
          .id('safety-item-title-input')
          .width('100%')
          .height(44)
          .fontSize(14)
          .borderRadius(Theme.radiusButton)
          .backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formTitle = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
        Text('类型').fontSize(13).fontColor(Theme.textSecondary)
        Row({ space: 8 }) {
          ForEach(ITEM_TYPES, (t: SafetyItemType) => {
            Text(this.typeLabel(t))
              .fontSize(13)
              .fontColor(this.formType === t ? '#FFFFFF' : Theme.textPrimary)
              .padding({ left: 12, right: 12, top: 8, bottom: 8 })
              .borderRadius(Theme.radiusButton)
              .backgroundColor(this.formType === t ? Theme.brandPrimary : Theme.chipSoftBg)
              .onClick(() => this.formType = t)
          }, (t: SafetyItemType) => t)
        }
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
        Text('截止日期').fontSize(13).fontColor(Theme.textSecondary)
        TextInput({ text: this.formDeadline, placeholder: 'YYYY-MM-DD（选填）' })
          .id('safety-item-deadline-picker')
          .width('100%')
          .height(44)
          .fontSize(14)
          .borderRadius(Theme.radiusButton)
          .backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formDeadline = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
        Text('描述').fontSize(13).fontColor(Theme.textSecondary)
        TextArea({ text: this.formDescription, placeholder: '补充说明（选填）' })
          .id('safety-item-description-input')
          .width('100%')
          .height(80)
          .fontSize(14)
          .borderRadius(Theme.radiusButton)
          .backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formDescription = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Button('保存')
        .id('safety-item-save-button')
        .width('100%')
        .height(46)
        .backgroundColor(Theme.brandPrimary)
        .fontColor('#FFFFFF')
        .fontSize(15)
        .borderRadius(Theme.radiusButton)
        .onClick(() => this.saveSafetyItem())
    }
    .width('100%')
    .height('100%')
    .padding(20)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }

  private typeLabel(t: SafetyItemType): string {
    if (t === 'fire') {
      return '消防';
    } else if (t === 'equipment') {
      return '设备';
    } else if (t === 'passage') {
      return '通道';
    } else if (t === 'training') {
      return '培训';
    }
    return '其他';
  }
}

