import { picker } from '@kit.CoreFileKit';
import { Theme } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import {
  Hazard, RiskLevel, HazardStatus,
  riskLevelLabel, riskLevelColor, hazardStatusLabel, hazardStatusColor, formatDate, isHazardOpen
} from '../model/Types';
import { EmptyState, StatusBadge, PageHeader } from '../components/Common';
import { showToast } from '../common/Toast';

const LEVEL_FILTERS: RiskLevel[] = ['low', 'medium', 'high', 'critical'];
const STATUS_FILTERS: string[] = ['all', 'open', 'closed'];

@Component
export struct HazardsPage {
  startRectification: () => void = () => {};

  @State hazards: Hazard[] = [];
  @State levelFilter: RiskLevel | 'all' = 'all';
  @State statusFilter: string = 'all';
  @State showReportSheet: boolean = false;
  @State selectedHazard: Hazard | null = null;

  @State formTitle: string = '';
  @State formLevel: RiskLevel = 'medium';
  @State formLocation: string = '';
  @State formDescription: string = '';
  @State formPhotos: string[] = [];

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
    this.hazards = this.store.hazards.slice().sort((a: Hazard, b: Hazard) => b.createdAt - a.createdAt);
  }

  private filteredHazards(): Hazard[] {
    return this.hazards.filter((h: Hazard) => {
      if (this.levelFilter !== 'all' && h.level !== this.levelFilter) {
        return false;
      }
      if (this.statusFilter === 'open' && !isHazardOpen(h.status)) {
        return false;
      }
      if (this.statusFilter === 'closed' && h.status !== 'closed') {
        return false;
      }
      return true;
    });
  }

  private pickPhoto(): void {
    try {
      const photoPicker: picker.PhotoViewPicker = new picker.PhotoViewPicker();
      const options: picker.PhotoSelectOptions = new picker.PhotoSelectOptions();
      options.maxSelectNumber = 3;
      photoPicker.select(options).then((result: picker.PhotoSelectResult) => {
        this.formPhotos = result.photoUris;
        showToast('已选择 ' + this.formPhotos.length + ' 张照片');
      }).catch(() => {
        showToast('未选择照片');
      });
    } catch (e) {
      showToast('相册不可用');
    }
  }

  private submitHazard(): void {
    if (this.formTitle.trim().length === 0) {
      showToast('请填写隐患标题');
      return;
    }
    this.store.addHazard(this.formTitle.trim(), this.formLevel, this.formLocation.trim(), this.formDescription.trim(), this.formPhotos.slice());
    this.formTitle = '';
    this.formLevel = 'medium';
    this.formLocation = '';
    this.formDescription = '';
    this.formPhotos = [];
    this.showReportSheet = false;
    this.refresh();
    showToast('隐患已上报');
  }

  private openDetail(h: Hazard): void {
    this.selectedHazard = h;
  }

  private startRect(h: Hazard): void {
    this.store.startRectificationForHazard(h);
    this.selectedHazard = null;
    this.refresh();
    showToast('已发起整改，已跳转整改页');
    this.startRectification();
  }

  build() {
    Column() {
      this.TopBar()
      this.Filters()
      Scroll() {
        Column({ space: 10 }) {
          if (this.filteredHazards().length === 0) {
            EmptyState({ title: '暂无隐患', hint: '点击右下角「+」上报隐患' })
              .id('hazards-empty')
          } else {
            ForEach(this.filteredHazards(), (h: Hazard) => {
              this.HazardCard(h)
            }, (h: Hazard) => h.id)
          }
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 96 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      this.FabAdd()
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
    .bindSheet($$this.showReportSheet, this.ReportSheet(), { height: '78%', dragBar: true })
    .bindSheet($$this.detailVisible(), this.DetailSheet(), { height: '55%', dragBar: true })
  }

  private detailVisible(): boolean {
    return this.selectedHazard !== null;
  }

  @Builder
  TopBar() {
    Row() {
      Text('风险隐患')
        .fontSize(20)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .layoutWeight(1)
      Text('上报')
        .id('hazards-add-button')
        .fontSize(14)
        .fontColor('#FFFFFF')
        .padding({ left: 14, right: 14, top: 8, bottom: 8 })
        .borderRadius(Theme.radiusButton)
        .backgroundColor(Theme.brandPrimary)
        .onClick(() => {
          this.showReportSheet = true;
        })
    }
    .width('100%')
    .height(56)
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .alignItems(VerticalAlign.Center)
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  Filters() {
    Column({ space: 8 }) {
      Scroll() {
        Row({ space: 8 }) {
          Text('全部')
            .id('hazards-filter-level')
            .fontSize(13)
            .fontColor(this.levelFilter === 'all' ? '#FFFFFF' : Theme.textPrimary)
            .padding({ left: 12, right: 12, top: 7, bottom: 7 })
            .borderRadius(Theme.radiusButton)
            .backgroundColor(this.levelFilter === 'all' ? Theme.brandPrimary : Theme.chipSoftBg)
            .onClick(() => this.levelFilter = 'all')
          ForEach(LEVEL_FILTERS, (lv: RiskLevel) => {
            Text(riskLevelLabel(lv))
              .fontSize(13)
              .fontColor(this.levelFilter === lv ? '#FFFFFF' : Theme.textPrimary)
              .padding({ left: 12, right: 12, top: 7, bottom: 7 })
              .borderRadius(Theme.radiusButton)
              .backgroundColor(this.levelFilter === lv ? Theme.brandPrimary : Theme.chipSoftBg)
              .onClick(() => this.levelFilter = lv)
          }, (lv: RiskLevel) => lv)
        }.padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
      }.scrollable(ScrollDirection.Horizontal).scrollBar(BarState.Off).width('100%')
      Row({ space: 8 }) {
        ForEach(STATUS_FILTERS, (s: string) => {
          Text(this.statusLabel(s))
            .id(s === 'all' ? 'hazards-filter-status' : 'hazards-filter-status-' + s)
            .fontSize(13)
            .fontColor(this.statusFilter === s ? '#FFFFFF' : Theme.textPrimary)
            .padding({ left: 12, right: 12, top: 7, bottom: 7 })
            .borderRadius(Theme.radiusButton)
            .backgroundColor(this.statusFilter === s ? Theme.brandDark : Theme.chipSoftBg)
            .onClick(() => this.statusFilter = s)
        }, (s: string) => s)
      }.width('100%').padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    }
    .width('100%')
    .padding({ top: 10, bottom: 10 })
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  HazardCard(h: Hazard) {
    Column({ space: 8 }) {
      Row() {
        Text(h.title)
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
          .layoutWeight(1)
          .maxLines(1)
          .textOverflow({ overflow: TextOverflow.Ellipsis })
        StatusBadge({ label: riskLevelLabel(h.level), color: riskLevelColor(h.level) })
      }.width('100%').alignItems(VerticalAlign.Center)
      Row({ space: 6 }) {
        Text(h.location.length > 0 ? h.location : '位置未填')
          .fontSize(12).fontColor(Theme.textTertiary).layoutWeight(1)
        StatusBadge({ label: hazardStatusLabel(h.status), color: hazardStatusColor(h.status) })
      }.width('100%')
      Row() {
        Text(formatDate(h.createdAt)).fontSize(12).fontColor(Theme.textQuaternary)
        Blank()
        Text('查看详情 ›').fontSize(12).fontColor(Theme.brandPrimary)
      }.width('100%')
    }
    .id('hazard-' + h.id)
    .width('100%')
    .padding(14)
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
    .onClick(() => this.openDetail(h))
  }

  @Builder
  FabAdd() {
    Row() {
      Text('+')
        .fontSize(28)
        .fontColor('#FFFFFF')
        .width(52).height(52)
        .textAlign(TextAlign.Center)
        .borderRadius(26)
        .backgroundColor(Theme.brandPrimary)
        .alignItems(VerticalAlign.Center)
        .justifyContent(FlexAlign.Center)
    }
    .width('100%')
    .padding({ right: 20, bottom: 12 })
    .justifyContent(FlexAlign.End)
  }

  @Builder
  ReportSheet() {
    Scroll() {
      Column({ space: 14 }) {
        Text('隐患上报').fontSize(17).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)

        Column({ space: 8 }) {
          Text('标题').fontSize(13).fontColor(Theme.textSecondary)
          TextInput({ text: this.formTitle, placeholder: '简述隐患' })
            .id('hazard-title-input')
            .width('100%').height(44).fontSize(14)
            .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
            .onChange((v: string) => this.formTitle = v)
        }.width('100%').alignItems(HorizontalAlign.Start)

        Column({ space: 8 }) {
          Text('风险等级').fontSize(13).fontColor(Theme.textSecondary)
          Row({ space: 8 }) {
            ForEach(LEVEL_FILTERS, (lv: RiskLevel) => {
              Text(riskLevelLabel(lv))
                .id('hazard-level-picker')
                .fontSize(13)
                .fontColor(this.formLevel === lv ? '#FFFFFF' : riskLevelColor(lv))
                .padding({ left: 14, right: 14, top: 8, bottom: 8 })
                .borderRadius(Theme.radiusButton)
                .backgroundColor(this.formLevel === lv ? riskLevelColor(lv) : Theme.chipSoftBg)
                .onClick(() => this.formLevel = lv)
            }, (lv: RiskLevel) => lv)
          }
        }.width('100%').alignItems(HorizontalAlign.Start)

        Column({ space: 8 }) {
          Text('位置').fontSize(13).fontColor(Theme.textSecondary)
          TextInput({ text: this.formLocation, placeholder: '发生位置（选填）' })
            .id('hazard-location-input')
            .width('100%').height(44).fontSize(14)
            .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
            .onChange((v: string) => this.formLocation = v)
        }.width('100%').alignItems(HorizontalAlign.Start)

        Column({ space: 8 }) {
          Text('描述').fontSize(13).fontColor(Theme.textSecondary)
          TextArea({ text: this.formDescription, placeholder: '详细描述（选填）' })
            .id('hazard-description-input')
            .width('100%').height(80).fontSize(14)
            .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
            .onChange((v: string) => this.formDescription = v)
        }.width('100%').alignItems(HorizontalAlign.Start)

        Column({ space: 8 }) {
          Text('现场照片').fontSize(13).fontColor(Theme.textSecondary)
          Row({ space: 10 }) {
            Text(this.formPhotos.length > 0 ? ('已选 ' + this.formPhotos.length + ' 张') : '选择照片')
              .id('hazard-photo-picker')
              .fontSize(13)
              .fontColor(Theme.brandPrimary)
              .padding({ left: 14, right: 14, top: 9, bottom: 9 })
              .borderRadius(Theme.radiusButton)
              .backgroundColor(Theme.chipSelectedBg)
              .onClick(() => this.pickPhoto())
          }.width('100%')
        }.width('100%').alignItems(HorizontalAlign.Start)

        Button('提交上报')
          .id('hazard-submit-button')
          .width('100%').height(46)
          .backgroundColor(Theme.brandPrimary).fontColor('#FFFFFF').fontSize(15)
          .borderRadius(Theme.radiusButton)
          .onClick(() => this.submitHazard())
      }
      .width('100%')
      .padding(20)
      .backgroundColor(Theme.cardBg)
      .alignItems(HorizontalAlign.Start)
    }
    .width('100%')
    .height('100%')
    .scrollBar(BarState.Off)
  }

  @Builder
  DetailSheet() {
    Column({ space: 12 }) {
      if (this.selectedHazard !== null) {
        Text(this.selectedHazard.title).fontSize(18).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Row() {
          Text('当前状态：').fontSize(13).fontColor(Theme.textSecondary)
          Text(hazardStatusLabel(this.selectedHazard.status))
            .id('hazard-detail-status-label')
            .fontSize(13).fontWeight(FontWeight.Medium).fontColor(hazardStatusColor(this.selectedHazard.status))
        }.width('100%')
        Row({ space: 8 }) {
          StatusBadge({ label: riskLevelLabel(this.selectedHazard.level), color: riskLevelColor(this.selectedHazard.level) })
          Text(this.selectedHazard.location.length > 0 ? this.selectedHazard.location : '位置未填')
            .fontSize(12).fontColor(Theme.textTertiary)
        }.width('100%')
        if (this.selectedHazard.description.length > 0) {
          Text(this.selectedHazard.description).fontSize(13).fontColor(Theme.textSecondary).width('100%')
        }
        Text('上报时间：' + formatDate(this.selectedHazard.createdAt)).fontSize(12).fontColor(Theme.textQuaternary)
        if (isHazardOpen(this.selectedHazard.status)) {
          Button('发起整改')
            .id('hazard-detail-rectify-button')
            .width('100%').height(46)
            .backgroundColor(Theme.brandPrimary).fontColor('#FFFFFF').fontSize(15)
            .borderRadius(Theme.radiusButton)
            .onClick(() => this.startRect(this.selectedHazard as Hazard))
        }
      }
    }
    .width('100%')
    .padding(20)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }

  private statusLabel(s: string): string {
    if (s === 'open') {
      return '未闭环';
    } else if (s === 'closed') {
      return '已闭环';
    }
    return '全部';
  }
}

