import { Theme } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import { PatrolTask, PatrolRecord, formatDate, startOfDay } from '../model/Types';
import { EmptyState, StatusBadge, SectionHeader } from '../components/Common';
import { showToast } from '../common/Toast';

@Component
export struct PatrolPage {
  @State currentLocation: string = '默认责任区域';
  @State todayCount: number = 0;
  @State patrolTasks: PatrolTask[] = [];
  @State history: PatrolRecord[] = [];

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
    this.todayCount = this.store.patrolTodayCount();
    this.patrolTasks = this.store.patrolTasks.slice();
    this.history = this.store.patrolRecords.slice().sort((a: PatrolRecord, b: PatrolRecord) => b.createdAt - a.createdAt);
  }

  private checkIn(): void {
    this.store.addPatrolRecord(this.currentLocation.trim().length > 0 ? this.currentLocation : '默认责任区域', '');
    this.refresh();
    showToast('巡检打卡成功');
  }

  private checkInTask(t: PatrolTask): void {
    this.store.checkInPatrolTask(t.id);
    this.refresh();
    showToast('已完成点位打卡：' + t.name);
  }

  build() {
    Column() {
      this.TopBar()
      Scroll() {
        Column({ space: 14 }) {
          this.CheckInBoard()
          this.TasksSection()
          this.HistorySection()
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 24 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  TopBar() {
    Row() {
      Text('巡检打卡')
        .fontSize(20)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .layoutWeight(1)
    }
    .width('100%')
    .height(56)
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .alignItems(VerticalAlign.Center)
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  CheckInBoard() {
    Column({ space: 14 }) {
      Row() {
        Column({ space: 4 }) {
          Text('当前位置')
            .fontSize(12)
            .fontColor('rgba(255,255,255,0.85)')
          Text(this.currentLocation)
            .id('patrol-location-text')
            .fontSize(16)
            .fontWeight(FontWeight.Medium)
            .fontColor('#FFFFFF')
        }
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)
        Column({ space: 2 }) {
          Text('今日打卡')
            .fontSize(12)
            .fontColor('rgba(255,255,255,0.85)')
          Row() {
            Text(this.todayCount.toString())
              .id('patrol-today-count')
              .fontSize(30)
              .fontWeight(FontWeight.Bold)
              .fontColor('#FFFFFF')
            Text('次')
              .fontSize(12)
              .fontColor('rgba(255,255,255,0.85)')
              .margin({ left: 2, bottom: 4 })
          }.alignItems(VerticalAlign.Bottom)
        }.alignItems(HorizontalAlign.End)
      }
      .width('100%')

      TextInput({ text: this.currentLocation, placeholder: '修改打卡位置/责任区域' })
        .width('100%')
        .height(44)
        .fontSize(14)
        .borderRadius(Theme.radiusButton)
        .backgroundColor('rgba(255,255,255,0.92)')
        .onChange((v: string) => this.currentLocation = v)

      Button('立即打卡')
        .id('patrol-check-in-button')
        .width('100%')
        .height(48)
        .backgroundColor('#FFFFFF')
        .fontColor(Theme.brandPrimary)
        .fontSize(16)
        .fontWeight(FontWeight.Bold)
        .borderRadius(Theme.radiusButton)
        .onClick(() => this.checkIn())
    }
    .width('100%')
    .padding(16)
    .borderRadius(Theme.radiusCard)
    .linearGradient({
      angle: 135,
      direction: GradientDirection.RightTop,
      colors: [['#0E7C7B', 0.0], ['#0A4F5C', 1.0]]
    } as LinearGradient)
  }

  @Builder
  TasksSection() {
    Column({ space: 10 }) {
      SectionHeader({ title: '巡检点位' })
      if (this.patrolTasks.length === 0) {
        EmptyState({ title: '暂无巡检点位', hint: '前往后台配置巡检路线后此处可快速打卡' })
          .id('patrol-tasks-empty')
      } else {
        Column({ space: 10 }) {
          ForEach(this.patrolTasks, (t: PatrolTask) => {
            Row() {
              Column({ space: 4 }) {
                Text(t.name).fontSize(15).fontColor(Theme.textPrimary).fontWeight(FontWeight.Medium)
                Text(t.location).fontSize(12).fontColor(Theme.textTertiary)
              }
              .alignItems(HorizontalAlign.Start)
              .layoutWeight(1)
              Text(t.done ? '已打卡' : '打卡')
                .id('patrol-task-check-in-button')
                .fontSize(13)
                .fontColor(t.done ? Theme.textQuaternary : '#FFFFFF')
                .padding({ left: 14, right: 14, top: 8, bottom: 8 })
                .borderRadius(Theme.radiusButton)
                .backgroundColor(t.done ? Theme.chipSoftBg : Theme.brandPrimary)
                .onClick(() => {
                  if (!t.done) {
                    this.checkInTask(t);
                  }
                })
            }
            .id('patrol-task-' + t.id)
            .width('100%')
            .padding(14)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBg)
            .alignItems(VerticalAlign.Center)
          }, (t: PatrolTask) => t.id)
        }
        .id('patrol-task-list')
        .width('100%')
      }
    }
  }

  @Builder
  HistorySection() {
    Column({ space: 10 }) {
      SectionHeader({ title: '打卡历史' })
      if (this.history.length === 0) {
        EmptyState({ title: '暂无打卡记录', hint: '完成首次巡检打卡后将显示在此' })
          .id('patrol-history-empty')
      } else {
        Column({ space: 8 }) {
          ForEach(this.history.slice(0, 30), (r: PatrolRecord) => {
            Row() {
              Column({ space: 3 }) {
                Text(r.location.length > 0 ? r.location : '巡检打卡')
                  .fontSize(14).fontColor(Theme.textPrimary)
                Text(formatDate(r.createdAt)).fontSize(12).fontColor(Theme.textTertiary)
              }
              .alignItems(HorizontalAlign.Start)
              .layoutWeight(1)
              StatusBadge({ label: '已完成', color: Theme.success })
            }
            .id('patrol-record-' + r.id)
            .width('100%')
            .padding(12)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBg)
            .alignItems(VerticalAlign.Center)
          }, (r: PatrolRecord) => r.id)
        }
        .id('patrol-history-list')
        .width('100%')
      }
    }
  }
}

