import { Theme } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import { PatrolTask, PatrolRecord, formatDate, startOfDay } from '../model/Types';
import { EmptyState, StatusBadge, SectionHeader } from '../components/Common';
import { showToast } from '../common/Toast';

@Component
export struct PatrolPage {
  @State currentLocation: string = '默认责任区域';
  @State todayCount: number = 0;
  @State patrolTasks: PatrolTask[] = [];
  @State history: PatrolRecord[] = [];

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
