        Column({ space: 4 }) {
          Text('当前位置')
            .fontSize(12)
            .fontColor('rgba(255,255,255,0.85)')
          Text(this.currentLocation)
            .id('patrol-location-text')
            .fontSize(16)
            .fontWeight(FontWeight.Medium)
            .fontColor('#FFFFFF')
