          .id('patrol-history-empty')
      } else {
        Column({ space: 8 }) {
          ForEach(this.history.slice(0, 30), (r: PatrolRecord) => {
            Row() {
              Column({ space: 3 }) {
                Text(r.location.length > 0 ? r.location : '巡检打卡')
                  .fontSize(14).fontColor(Theme.textPrimary)
                Text(formatDate(r.createdAt)).fontSize(12).fontColor(Theme.textTertiary)
              }
              .alignItems(HorizontalAlign.Start)
              .layoutWeight(1)
              StatusBadge({ label: '已完成', color: Theme.success })
            }
            .id('patrol-record-' + r.id)
            .width('100%')
            .padding(12)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBg)
            .alignItems(VerticalAlign.Center)
          }, (r: PatrolRecord) => r.id)
        }
        .id('patrol-history-list')
        .width('100%')
      }
    }
  }
}

