  @State formStatus: RectificationStatus = 'in_progress';
  @State formRemark: string = '';

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
    this.rectifications = this.store.rectifications.slice().sort((a: Rectification, b: Rectification) => b.createdAt - a.createdAt);
  }

  private filtered(): Rectification[] {
    if (this.statusFilter === 'all') {
      return this.rectifications;
    }
    return this.rectifications.filter((r: Rectification) => r.status === this.statusFilter);
  }

  private openUpdate(r: Rectification): void {
    this.editingId = r.id;
    this.formAssignee = r.assignee;
    this.formDeadline = r.deadline;
    this.formStatus = r.status === 'pending' ? 'in_progress' : r.status;
    this.formRemark = r.remark;
    this.showSheet = true;
  }

  private saveProgress(): void {
    this.store.updateRectification(this.editingId, this.formAssignee.trim(), this.formDeadline.trim(), this.formStatus, this.formRemark.trim());
    this.showSheet = false;
    this.refresh();
    showToast('整改进度已更新');
  }

  build() {
    Column() {
      this.TopBar()
      this.RateSummary()
      this.Filters()
      Scroll() {
        Column({ space: 10 }) {
          if (this.filtered().length === 0) {
            EmptyState({ title: '暂无整改任务', hint: '在隐患详情中点击「发起整改」生成任务' })
              .id('rectification-empty')
          } else {
            ForEach(this.filtered(), (r: Rectification) => {
              this.RectificationCard(r)
            }, (r: Rectification) => r.id)
          }
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 24 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
    .bindSheet($$this.showSheet, this.UpdateSheet(), { height: '70%', dragBar: true })
  }

  @Builder
  TopBar() {
    Row() {
      Text('整改进度')
        .fontSize(20)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .layoutWeight(1)
    }
    .width('100%')
    .height(56)
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .alignItems(VerticalAlign.Center)
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  RateSummary() {
    Row() {
      Column({ space: 2 }) {
        Text('整改闭环率').fontSize(12).fontColor(Theme.textSecondary)
        Row() {
          Text(this.store.rectificationRate().toString())
            .id('rectification-progress-rate')
            .fontSize(26).fontWeight(FontWeight.Bold).fontColor(Theme.brandPrimary)
          Text('%').fontSize(12).fontColor(Theme.textTertiary).margin({ left: 2, bottom: 4 })
        }.alignItems(VerticalAlign.Bottom)
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)
      Column({ space: 2 }) {
        Text('整改任务').fontSize(12).fontColor(Theme.textSecondary)
        Text(this.rectifications.length.toString()).fontSize(26).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
      }
      .alignItems(HorizontalAlign.End)
    }
    .width('100%')
    .padding(16)
    .margin({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 10 })
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(VerticalAlign.Center)
  }

  @Builder
  Filters() {
    Scroll() {
      Row({ space: 8 }) {
        ForEach(FILTER_OPTIONS, (s: string) => {
          Text(this.filterLabel(s))
            .id(s === 'all' ? 'rectification-filter-status' : 'rectification-filter-status-' + s)
            .fontSize(13)
            .fontColor(this.statusFilter === s ? '#FFFFFF' : Theme.textPrimary)
            .padding({ left: 12, right: 12, top: 7, bottom: 7 })
            .borderRadius(Theme.radiusButton)
            .backgroundColor(this.statusFilter === s ? Theme.brandPrimary : Theme.chipSoftBg)
            .onClick(() => this.statusFilter = s)
        }, (s: string) => s)
      }
      .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 10, bottom: 10 })
    }
    .scrollable(ScrollDirection.Horizontal)
    .scrollBar(BarState.Off)
    .width('100%')
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  RectificationCard(r: Rectification) {
    Column({ space: 8 }) {
      Row() {
        Text(r.sourceTitle.length > 0 ? r.sourceTitle : '整改任务')
          .fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary)
          .layoutWeight(1).maxLines(1).textOverflow({ overflow: TextOverflow.Ellipsis })
        StatusBadge({ label: rectificationStatusLabel(r.status), color: rectificationStatusColor(r.status) })
      }.width('100%')
      Row({ space: 6 }) {
        Text('责任人：' + (r.assignee.length > 0 ? r.assignee : '未分配')).fontSize(12).fontColor(Theme.textTertiary).layoutWeight(1)
        if (r.deadline.length > 0) {
          Text('截止 ' + r.deadline).fontSize(12).fontColor(Theme.textTertiary)
        }
      }.width('100%')
      if (r.remark.length > 0) {
        Text(r.remark).fontSize(12).fontColor(Theme.textSecondary).width('100%')
      }
      Text('创建于 ' + formatDate(r.createdAt)).fontSize(11).fontColor(Theme.textQuaternary)
      Button('更新进度')
        .id('rectification-update-progress-button')
        .type(ButtonType.Normal)
        .width('100%').height(40)
        .backgroundColor(Theme.chipSelectedBg).fontColor(Theme.brandPrimary).fontSize(14)
        .borderRadius(Theme.radiusButton)
        .margin({ top: 4 })
        .onClick(() => this.openUpdate(r))
    }
    .id('rectification-' + r.id)
    .width('100%')
    .padding(14)
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  UpdateSheet() {
    Column({ space: 14 }) {
      Text('更新整改进度').fontSize(17).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)

      Column({ space: 8 }) {
        Text('责任人').fontSize(13).fontColor(Theme.textSecondary)
        TextInput({ text: this.formAssignee, placeholder: '整改负责人' })
          .id('rectification-assignee-picker')
          .width('100%').height(44).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formAssignee = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
        Text('截止日期').fontSize(13).fontColor(Theme.textSecondary)
        TextInput({ text: this.formDeadline, placeholder: 'YYYY-MM-DD（选填）' })
          .id('rectification-deadline-picker')
          .width('100%').height(44).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formDeadline = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
        Text('状态').fontSize(13).fontColor(Theme.textSecondary)
        Row({ space: 8 }) {
          ForEach(STATUS_OPTIONS, (s: RectificationStatus) => {
            Text(rectificationStatusLabel(s))
              .id('rectification-status-picker')
              .fontSize(13)
              .fontColor(this.formStatus === s ? '#FFFFFF' : Theme.textPrimary)
              .padding({ left: 12, right: 12, top: 8, bottom: 8 })
              .borderRadius(Theme.radiusButton)
              .backgroundColor(this.formStatus === s ? Theme.brandPrimary : Theme.chipSoftBg)
              .onClick(() => this.formStatus = s)
          }, (s: RectificationStatus) => s)
        }
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
        Text('备注').fontSize(13).fontColor(Theme.textSecondary)
        TextArea({ text: this.formRemark, placeholder: '整改说明 / 验收意见' })
          .id('rectification-remark-input')
          .width('100%').height(80).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formRemark = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Button('保存')
        .id('rectification-save-button')
        .width('100%').height(46)
        .backgroundColor(Theme.brandPrimary).fontColor('#FFFFFF').fontSize(15)
        .borderRadius(Theme.radiusButton)
        .onClick(() => this.saveProgress())
    }
    .width('100%')
    .height('100%')
    .padding(20)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }

  private filterLabel(s: string): string {
    if (s === 'all') {
      return '全部';
    } else if (s === 'pending') {
      return '待整改';
    } else if (s === 'in_progress') {
      return '整改中';
    } else if (s === 'pending_accept') {
      return '待验收';
    }
    return '已闭环';
  }
}

