import { call } from '@kit.TelephonyKit';
import { Theme } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import { Contact } from '../model/Types';
import { EmptyState, PageHeader } from '../components/Common';
import { showToast } from '../common/Toast';

@Component
export struct ContactsPage {
  onBack: () => void = () => {};

  @State contacts: Contact[] = [];
  @State showAddSheet: boolean = false;

  @State formName: string = '';
  @State formRole: string = '';
  @State formPhone: string = '';

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
    this.contacts = this.store.contacts.slice();
  }

  private saveContact(): void {
    if (this.formName.trim().length === 0) {
      showToast('请填写联系人姓名');
      return;
    }
    if (this.formPhone.trim().length === 0) {
      showToast('请填写联系电话');
      return;
    }
    this.store.addContact(this.formName.trim(), this.formRole.trim(), this.formPhone.trim());
    this.formName = '';
    this.formRole = '';
    this.formPhone = '';
    this.showAddSheet = false;
    this.refresh();
    showToast('联系人已保存');
  }

  private callContact(c: Contact): void {
    try {
      call.makeCall(c.phone, (err: Error) => {
        if (err) {
          showToast('拨号失败：' + c.phone);
        }
      });
    } catch (e) {
      showToast('拨号不可用：' + c.phone);
    }
  }

  private deleteContact(c: Contact): void {
    this.store.deleteContact(c.id);
    this.refresh();
    showToast('已删除联系人');
  }

  build() {
    Column() {
      PageHeader({
        title: '应急联系人',
        onBack: (): void => this.onBack(),
        actionText: '新增',
        onAction: (): void => {
          this.showAddSheet = true;
        }
      })
      Scroll() {
        Column({ space: 10 }) {
          if (this.contacts.length === 0) {
            EmptyState({ title: '暂无应急联系人', hint: '点击右上角「新增」添加安保/消防/医疗/管理联系人' })
              .id('contacts-empty')
          } else {
            Column({ space: 10 }) {
              ForEach(this.contacts, (c: Contact) => {
                this.ContactCard(c)
              }, (c: Contact) => c.id)
            }
            .id('contacts-list')
            .width('100%')
          }
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 24 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
    .bindSheet($$this.showAddSheet, this.AddSheet(), { height: '60%', dragBar: true })
  }

  @Builder
  ContactCard(c: Contact) {
    Row() {
      Column({ space: 4 }) {
        Text(c.name).fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary)
        Row({ space: 8 }) {
          if (c.role.length > 0) {
            Text(c.role).fontSize(12).fontColor(Theme.brandPrimary)
          }
          Text(c.phone).fontSize(13).fontColor(Theme.textTertiary)
        }
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)
      Column({ space: 8 }) {
        Text('拨打')
          .id('contact-call-button')
          .fontSize(13).fontColor('#FFFFFF')
          .padding({ left: 16, right: 16, top: 9, bottom: 9 })
          .borderRadius(Theme.radiusButton)
          .backgroundColor(Theme.danger)
          .onClick(() => this.callContact(c))
        Text('删除')
          .id('contact-delete-button')
          .fontSize(12).fontColor(Theme.textQuaternary)
          .onClick(() => this.deleteContact(c))
      }
      .alignItems(HorizontalAlign.End)
    }
    .id('contact-' + c.id)
    .width('100%')
    .padding(14)
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(VerticalAlign.Center)
  }

  @Builder
  AddSheet() {
    Column({ space: 14 }) {
      Text('新增应急联系人').fontSize(17).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)

      Column({ space: 8 }) {
        Text('姓名').fontSize(13).fontColor(Theme.textSecondary)
        TextInput({ text: this.formName, placeholder: '如：安保中心' })
          .id('contact-name-input')
          .width('100%').height(44).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formName = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
        Text('角色/类别').fontSize(13).fontColor(Theme.textSecondary)
        TextInput({ text: this.formRole, placeholder: '安保 / 消防 / 医疗 / 管理' })
          .id('contact-role-input')
          .width('100%').height(44).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formRole = v)
      }.width('100%').alignItems(HorizontalAlign.Start)

      Column({ space: 8 }) {
