import { Theme } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import { SafetyItem, SafetyItemStatus, SafetyItemType, safetyItemTypeLabel, safetyItemStatusLabels, formatDateShort } from '../model/Types';
import { EmptyState, StatusBadge, PageHeader } from '../components/Common';
import { showToast } from '../common/Toast';

const ITEM_TYPES: SafetyItemType[] = ['fire', 'equipment', 'passage', 'training', 'other'];
const STATUS_FILTERS: string[] = ['all', 'open', 'in_progress', 'done'];

@Component
export struct SafetyItemsPage {
  onBack: () => void = () => {};

  @State items: SafetyItem[] = [];
  @State search: string = '';
  @State statusFilter: string = 'all';
  @State showAddSheet: boolean = false;

  @State formTitle: string = '';
  @State formType: SafetyItemType = 'fire';
  @State formDeadline: string = '';
  @State formDescription: string = '';

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
    this.items = this.store.safetyItems.slice().sort((a: SafetyItem, b: SafetyItem) => b.createdAt - a.createdAt);
  }

  private filtered(): SafetyItem[] {
    return this.items.filter((it: SafetyItem) => {
      if (this.statusFilter !== 'all' && it.status !== this.statusFilter) {
        return false;
      }
      if (this.search.trim().length > 0 && !it.title.includes(this.search.trim()) && !it.description.includes(this.search.trim())) {
        return false;
      }
      return true;
    });
  }

  private saveItem(): void {
    if (this.formTitle.trim().length === 0) {
      showToast('请填写事项标题');
      return;
    }
    this.store.addSafetyItem(this.formTitle.trim(), this.formType, this.formDeadline.trim(), this.formDescription.trim());
    this.formTitle = '';
    this.formType = 'fire';
    this.formDeadline = '';
    this.formDescription = '';
    this.showAddSheet = false;
    this.refresh();
    showToast('已保存安全事项');
  }

  private deleteItem(it: SafetyItem): void {
    this.store.deleteSafetyItem(it.id);
    this.refresh();
    showToast('已删除');
  }

  private cycleStatus(it: SafetyItem): void {
    const next: SafetyItemStatus = it.status === 'open' ? 'in_progress' : (it.status === 'in_progress' ? 'done' : 'open');
    this.store.setSafetyItemStatus(it.id, next);
    this.refresh();
  }

  build() {
    Column() {
      PageHeader({
        title: '安全事项',
        onBack: (): void => this.onBack(),
        actionText: '新增',
        onAction: (): void => {
          this.showAddSheet = true;
        }
      })
      this.SearchAndFilter()
      Scroll() {
        Column({ space: 10 }) {
          if (this.filtered().length === 0) {
            EmptyState({ title: '暂无安全事项', hint: '记录日常安全事项，便于跟进闭环' })
              .id('safety-items-empty')
          } else {
            ForEach(this.filtered(), (it: SafetyItem) => {
              this.ItemCard(it)
            }, (it: SafetyItem) => it.id)
          }
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 24 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
    .bindSheet($$this.showAddSheet, this.AddSheet(), { height: '70%', dragBar: true })
  }

  @Builder
  SearchAndFilter() {
    Column({ space: 10 }) {
      TextInput({ text: this.search, placeholder: '搜索安全事项' })
        .id('safety-items-search-input')
        .width('100%')
        .height(42)
        .fontSize(14)
        .borderRadius(Theme.radiusButton)
        .backgroundColor(Theme.cardBg)
        .onChange((v: string) => this.search = v)
      Scroll() {
        Row({ space: 8 }) {
          ForEach(STATUS_FILTERS, (s: string) => {
            Text(this.filterLabel(s))
              .id(s === 'all' ? 'safety-items-filter-status' : 'safety-items-filter-status-' + s)
              .fontSize(13)
              .fontColor(this.statusFilter === s ? '#FFFFFF' : Theme.textPrimary)
              .padding({ left: 12, right: 12, top: 7, bottom: 7 })
              .borderRadius(Theme.radiusButton)
              .backgroundColor(this.statusFilter === s ? Theme.brandPrimary : Theme.chipSoftBg)
              .onClick(() => this.statusFilter = s)
          }, (s: string) => s)
        }
      }
      .scrollable(ScrollDirection.Horizontal)
      .scrollBar(BarState.Off)
      .width('100%')
    }
    .width('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 10, bottom: 10 })
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  ItemCard(it: SafetyItem) {
    Column({ space: 8 }) {
      Row() {
        Column({ space: 4 }) {
          Text(safetyItemTypeLabel(it.type))
            .fontSize(11)
            .fontColor(Theme.brandPrimary)
            .padding({ left: 8, right: 8, top: 3, bottom: 3 })
            .borderRadius(Theme.radiusTiny)
            .backgroundColor(Theme.chipSelectedBg)
          Text(it.title).fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary).maxLines(2)
        }
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)
        StatusBadge({ label: safetyItemStatusLabels(it.status), color: this.statusColor(it.status) })
      }.width('100%').alignItems(VerticalAlign.Top)
      if (it.description.length > 0) {
        Text(it.description).fontSize(12).fontColor(Theme.textSecondary).maxLines(2).width('100%')
      }
      Row() {
        Text(it.deadline.length > 0 ? ('截止 ' + it.deadline) : '无截止').fontSize(11).fontColor(Theme.textQuaternary)
        Text('创建 ' + formatDateShort(it.createdAt)).fontSize(11).fontColor(Theme.textQuaternary).margin({ left: 10 })
        Blank()
        Text('切换状态').fontSize(12).fontColor(Theme.brandPrimary).onClick(() => this.cycleStatus(it))
        Text('删除')
          .id('safety-item-delete-button')
          .fontSize(12).fontColor(Theme.danger).margin({ left: 14 })
          .onClick(() => this.deleteItem(it))
      }.width('100%')
    }
    .id('safety-item-' + it.id)
    .width('100%')
    .padding(14)
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  AddSheet() {
    Column({ space: 14 }) {
      Text('新建安全事项').fontSize(17).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
      Column({ space: 8 }) {
        Text('标题').fontSize(13).fontColor(Theme.textSecondary)
        TextInput({ text: this.formTitle, placeholder: '如：设备异响待检修' })
          .id('safety-item-title-input')
          .width('100%').height(44).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formTitle = v)
      }.width('100%').alignItems(HorizontalAlign.Start)
      Column({ space: 8 }) {
        Text('类型').fontSize(13).fontColor(Theme.textSecondary)
        Row({ space: 8 }) {
          ForEach(ITEM_TYPES, (t: SafetyItemType) => {
            Text(safetyItemTypeLabel(t))
              .id('safety-item-type-picker')
              .fontSize(13)
              .fontColor(this.formType === t ? '#FFFFFF' : Theme.textPrimary)
              .padding({ left: 12, right: 12, top: 8, bottom: 8 })
              .borderRadius(Theme.radiusButton)
              .backgroundColor(this.formType === t ? Theme.brandPrimary : Theme.chipSoftBg)
              .onClick(() => this.formType = t)
          }, (t: SafetyItemType) => t)
        }
      }.width('100%').alignItems(HorizontalAlign.Start)
      Column({ space: 8 }) {
        Text('截止日期').fontSize(13).fontColor(Theme.textSecondary)
        TextInput({ text: this.formDeadline, placeholder: 'YYYY-MM-DD（选填）' })
          .id('safety-item-deadline-picker')
          .width('100%').height(44).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formDeadline = v)
      }.width('100%').alignItems(HorizontalAlign.Start)
      Column({ space: 8 }) {
        Text('描述').fontSize(13).fontColor(Theme.textSecondary)
        TextArea({ text: this.formDescription, placeholder: '补充说明（选填）' })
          .id('safety-item-description-input')
          .width('100%').height(80).fontSize(14)
          .borderRadius(Theme.radiusButton).backgroundColor(Theme.chipSoftBg)
          .onChange((v: string) => this.formDescription = v)
      }.width('100%').alignItems(HorizontalAlign.Start)
      Button('保存')
        .id('safety-item-save-button')
        .width('100%').height(46)
        .backgroundColor(Theme.brandPrimary).fontColor('#FFFFFF').fontSize(15)
        .borderRadius(Theme.radiusButton)
        .onClick(() => this.saveItem())
    }
    .width('100%').height('100%').padding(20).backgroundColor(Theme.cardBg).alignItems(HorizontalAlign.Start)
  }

  private statusColor(s: SafetyItemStatus): string {
    if (s === 'done') {
      return Theme.success;
    } else if (s === 'in_progress') {
      return Theme.info;
    }
    return Theme.warning;
  }

  private filterLabel(s: string): string {
    if (s === 'open') {
      return '待处理';
    } else if (s === 'in_progress') {
      return '进行中';
    } else if (s === 'done') {
      return '已完成';
    }
    return '全部';
  }
}

