        .onClick(() => this.saveItem())
    }
    .width('100%').height('100%').padding(20).backgroundColor(Theme.cardBg).alignItems(HorizontalAlign.Start)
  }

  private statusColor(s: SafetyItemStatus): string {
    if (s === 'done') {
      return Theme.success;
    } else if (s === 'in_progress') {
      return Theme.info;
    }
    return Theme.warning;
  }

  private filterLabel(s: string): string {
    if (s === 'open') {
      return '待处理';
    } else if (s === 'in_progress') {
      return '进行中';
    } else if (s === 'done') {
      return '已完成';
    }
    return '全部';
  }
}

