import { Theme, BrandGradient } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import { showToast } from '../common/Toast';

@Component
export struct ProfilePage {
  goToContacts: () => void = () => {};
  goToDashboard: () => void = () => {};

  private store: DataStore = DataStore.getInstance();

  private openSettings(): void {
    showToast('设置功能开发中');
  }

  build() {
    Column() {
      this.TopBar()
      Scroll() {
        Column({ space: 14 }) {
          this.ProfileCard()
          this.Entries()
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 24 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  TopBar() {
    Row() {
      Text('我的')
        .fontSize(20)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .layoutWeight(1)
    }
    .width('100%')
    .height(56)
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .alignItems(VerticalAlign.Center)
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  ProfileCard() {
    Row({ space: 14 }) {
      Text(this.store.profileName.charAt(0))
        .fontSize(24)
        .fontWeight(FontWeight.Bold)
        .fontColor('#FFFFFF')
        .width(56)
        .height(56)
        .textAlign(TextAlign.Center)
        .borderRadius(28)
        .backgroundColor('rgba(255,255,255,0.22)')
      Column({ space: 4 }) {
        Text(this.store.profileName)
          .id('profile-user-name')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor('#FFFFFF')
        Text('平安扣 · 一线安全员')
          .fontSize(12)
          .fontColor('rgba(255,255,255,0.85)')
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)
    }
    .width('100%')
    .padding(16)
    .borderRadius(Theme.radiusCard)
    .linearGradient(BrandGradient.primary)
    .alignItems(VerticalAlign.Center)
  }

  @Builder
  Entries() {
    Column({ space: 1 }) {
      this.EntryRow('profile-contacts-entry', '应急联系人', '管理与一键拨打应急联系人', () => this.goToContacts())
      this.EntryRow('profile-dashboard-entry', '统计看板', '隐患、整改、巡检数据汇总', () => this.goToDashboard())
      this.EntryRow('profile-settings-entry', '设置', '偏好与数据管理', () => this.openSettings())
    }
    .width('100%')
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  EntryRow(idValue: string, title: string, hint: string, action: () => void) {
    Row() {
      Column({ space: 4 }) {
        Text(title).fontSize(15).fontColor(Theme.textPrimary)
        Text(hint).fontSize(12).fontColor(Theme.textTertiary)
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)
      Text('›').fontSize(20).fontColor(Theme.textQuaternary)
    }
    .id(idValue)
    .width('100%')
    .padding({ top: 14, bottom: 14, left: 16, right: 16 })
    .backgroundColor(Theme.cardBg)
    .alignItems(VerticalAlign.Center)
    .onClick(() => action())
  }
}

