import { Theme } from '../common/Theme';
import { DataStore } from '../services/DataStore';
import { Hazard, RiskLevel, SafetyItemType, riskLevelLabel, riskLevelColor, safetyItemTypeLabel, startOfDay } from '../model/Types';
import { PageHeader, SectionHeader } from '../components/Common';
import { DashboardTimeRange } from '../model/Types';

interface BarItem {
  label: string;
  value: number;
  color: string;
}

@Component
export struct DashboardPage {
  onBack: () => void = () => {};

  @State timeRange: DashboardTimeRange = 'all';
  @State totalHazards: number = 0;
  @State pendingHazards: number = 0;
  @State rectificationRate: number = 0;
  @State patrolCount: number = 0;
  @State levelBars: BarItem[] = [];
  @State typeBars: BarItem[] = [];
  @State trendBars: BarItem[] = [];

  private store: DataStore = DataStore.getInstance();

  aboutToAppear(): void {
    this.refresh();
  }

  private refresh(): void {
    const hazards: Hazard[] = this.store.hazards;
    this.totalHazards = hazards.length;
    this.pendingHazards = this.store.pendingHazards();
    this.rectificationRate = this.store.rectificationRate();
    this.patrolCount = this.filteredPatrolCount();

    const levels: RiskLevel[] = ['critical', 'high', 'medium', 'low'];
    this.levelBars = levels.map((lv: RiskLevel): BarItem => {
      const cnt: number = hazards.filter((h: Hazard) => h.level === lv).length;
      return { label: riskLevelLabel(lv) + '风险', value: cnt, color: riskLevelColor(lv) };
    });

    const types: SafetyItemType[] = ['fire', 'equipment', 'passage', 'training', 'other'];
    const items = this.store.safetyItems;
    this.typeBars = types.map((t: SafetyItemType): BarItem => {
      const cnt: number = items.filter((it) => it.type === t).length;
      return { label: safetyItemTypeLabel(t), value: cnt, color: Theme.brandPrimary };
    });

    this.trendBars = this.buildTrend(hazards);
  }

  private filteredPatrolCount(): number {
    const records = this.store.patrolRecords;
    const now = Date.now();
    if (this.timeRange === 'week') {
      const from = now - 7 * 24 * 3600 * 1000;
      return records.filter((r) => r.createdAt >= from).length;
    } else if (this.timeRange === 'month') {
      const from = now - 30 * 24 * 3600 * 1000;
      return records.filter((r) => r.createdAt >= from).length;
    }
    return records.length;
  }

  private buildTrend(hazards: Hazard[]): BarItem[] {
    const today = startOfDay(Date.now());
    const colors: string[] = [Theme.brandPrimary, Theme.brandAccent, Theme.warning, Theme.danger, Theme.success, Theme.info, Theme.brandDark];
    const result: BarItem[] = [];
    for (let i = 6; i >= 0; i--) {
      const dayStart = today - i * 24 * 3600 * 1000;
      const dayEnd = dayStart + 24 * 3600 * 1000;
      const cnt = hazards.filter((h: Hazard) => h.createdAt >= dayStart && h.createdAt < dayEnd).length;
      const d = new Date(dayStart);
      const label: string = (d.getMonth() + 1).toString() + '/' + d.getDate().toString();
      result.push({ label: label, value: cnt, color: colors[(6 - i) % colors.length] });
    }
    return result;
  }

  build() {
    Column() {
      PageHeader({ title: '统计看板', onBack: (): void => this.onBack(), showBack: true })
      this.TimeRangePicker()
      Scroll() {
        Column({ space: 14 }) {
          this.MetricGrid()
          this.ChartSection('dashboard-level-chart', '隐患风险等级分布', this.levelBars, false)
          this.ChartSection('dashboard-type-chart', '安全事项类型分布', this.typeBars, false)
          this.ChartSection('dashboard-trend-chart', '近 7 天隐患趋势', this.trendBars, true)
        }
        .width('100%')
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 8, bottom: 24 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  TimeRangePicker() {
    Row({ space: 8 }) {
      ForEach([['week', '本周'], ['month', '本月'], ['all', '全部']] as [DashboardTimeRange, string][], (it: [DashboardTimeRange, string]) => {
        Text(it[1])
          .id('dashboard-time-range-picker')
          .fontSize(13)
          .fontColor(this.timeRange === it[0] ? '#FFFFFF' : Theme.textPrimary)
          .padding({ left: 14, right: 14, top: 7, bottom: 7 })
          .borderRadius(Theme.radiusButton)
          .backgroundColor(this.timeRange === it[0] ? Theme.brandPrimary : Theme.chipSoftBg)
          .onClick(() => {
            this.timeRange = it[0];
            this.refresh();
          })
      }, (it: [DashboardTimeRange, string]) => it[0])
    }
    .width('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 12, bottom: 12 })
    .backgroundColor(Theme.cardBg)
  }

  @Builder
  MetricGrid() {
    Grid() {
      GridItem() {
        this.Metric('dashboard-total-hazards', '隐患总数', this.totalHazards.toString(), Theme.danger)
      }
      GridItem() {
        this.Metric('dashboard-pending-hazards', '待整改隐患', this.pendingHazards.toString(), Theme.warning)
      }
      GridItem() {
        this.Metric('dashboard-rectification-rate', '整改闭环率', this.rectificationRate.toString() + '%', Theme.success)
      }
      GridItem() {
        this.Metric('dashboard-patrol-count', '巡检次数', this.patrolCount.toString(), Theme.info)
      }
    }
    .columnsTemplate('1fr 1fr')
    .rowsGap(10)
    .columnsGap(10)
    .height(150)
  }

  @Builder
  Metric(idValue: string, label: string, value: string, accent: string) {
    Column({ space: 6 }) {
      Text(label).fontSize(12).fontColor(Theme.textSecondary)
      Text(value).fontSize(24).fontWeight(FontWeight.Bold).fontColor(accent)
    }
    .id(idValue)
    .width('100%')
    .height('100%')
    .padding({ top: 14, bottom: 14, left: 14, right: 14 })
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
    .justifyContent(FlexAlign.Center)
  }

  @Builder
  ChartSection(chartId: string, title: string, bars: BarItem[], vertical: boolean) {
    Column({ space: 12 }) {
      SectionHeader({ title: title })
      if (vertical) {
        this.VerticalBars(chartId, bars)
      } else {
        this.HorizontalBars(bars)
      }
    }
    .id(chartId)
    .width('100%')
    .padding(14)
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  HorizontalBars(bars: BarItem[]) {
    Column({ space: 10 }) {
      ForEach(bars, (b: BarItem) => {
        this.BarRow(b)
      }, (b: BarItem, idx: number) => b.label + idx.toString())
    }.width('100%')
  }

  @Builder
  BarRow(b: BarItem) {
    Column({ space: 4 }) {
      Row() {
        Text(b.label).fontSize(12).fontColor(Theme.textSecondary).layoutWeight(1)
        Text(b.value.toString()).fontSize(12).fontColor(Theme.textPrimary).fontWeight(FontWeight.Medium)
      }.width('100%')
      Row() {
        Column()
          .width(this.barWidthPercent(b.value, this.maxValue(this.levelBars.concat(this.typeBars))))
          .height(8)
          .borderRadius(4)
          .backgroundColor(b.color)
      }.width('100%')
    }.width('100%')
  }

  @Builder
  VerticalBars(chartId: string, bars: BarItem[]) {
    Row() {
      ForEach(bars, (b: BarItem) => {
        Column({ space: 6 }) {
          Text(b.value.toString()).fontSize(11).fontColor(Theme.textPrimary)
          Column()
            .width(20)
            .height(this.trendHeight(b.value))
            .borderRadius(4)
            .backgroundColor(b.color)
          Text(b.label).fontSize(10).fontColor(Theme.textTertiary)
        }
        .layoutWeight(1)
        .justifyContent(FlexAlign.End)
        .alignItems(HorizontalAlign.Center)
      }, (b: BarItem, idx: number) => chartId + idx.toString())
    }
    .width('100%')
    .height(120)
    .alignItems(VerticalAlign.Bottom)
  }

  private barWidthPercent(value: number, max: number): string {
    if (max <= 0) {
      return '4%';
    }
    const pct = Math.max(4, Math.round(value / max * 100));
    return pct.toString() + '%';
  }

  private maxValue(bars: BarItem[]): number {
    let m = 0;
    bars.forEach((b: BarItem) => {
      if (b.value > m) {
        m = b.value;
      }
    });
    return m;
  }

  private trendHeight(value: number): number {
    const max = this.maxValue(this.trendBars);
    if (max <= 0) {
      return 4;
    }
    return Math.max(4, Math.round(value / max * 64));
  }
}
